mapper.update:
update base set update_time = now()

		, name = #{name}


		, exchange = #{exchange}


    	, is_st = #{isSt} 


    	, is_trade = #{isTrade}


    	, `close` = #{close}


    	, prev_close = #{prevClose}


    	, open = #{open}


    	, high = #{high}


    	, low = #{low}


    	, volume = #{volume}


    	, amount = #{amount}


    	, day = #{day}


    	, quancheng = #{quancheng}


    	, main_business = #{mainBusiness}


    	, business_scope = #{businessScope}


    	, business_brief = #{businessBrief}


    	, industry = #{industry}


    	, industry_csrc = #{industryCsrc}


    	, org_profile = #{orgProfile}


    	, pe_ttm = #{peTtm}


    	, pb = #{pb}


    	, ps_ttm = #{psTtm}


    	, dividend_yield = #{dividendYield}


    	, high_52w = #{high52w}


    	, low_52w = #{low52w}


    	, total_mv_yi = #{totalMvYi}


    	, turnover_rate = #{turnoverRate}

where code = #{code}

mapper.select:
    select s.code, s.name, s.`close`, s.open, s.high, s.low, s.is_st, s.day
    	from base s



	    			and s.code = #{code}
